// worker-order-service.js - Order service internal worker
export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/health') {
      return new Response(JSON.stringify({ status: 'healthy', service: 'order-service' }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (request.method === 'GET' && path === '/api/orders') {
      const orders = [
        { id: 1, userId: 1, productId: 1, quantity: 2, total: 59.98, status: 'completed' },
        { id: 2, userId: 2, productId: 2, quantity: 1, total: 49.99, status: 'pending' }
      ];

      return new Response(JSON.stringify({ orders }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (request.method === 'POST' && path === '/api/orders') {
      const body = await request.json();
      const { userId, productId, quantity } = body;

      let productData = null;
      if (env.PRODUCT_SERVICE) {
        const productResponse = await env.PRODUCT_SERVICE.fetch(
          new Request(`http://internal/api/products/${productId}`)
        );
        if (productResponse.ok) {
          const data = await productResponse.json();
          productData = data.product;
        }
      }

      let userData = null;
      if (env.USER_SERVICE) {
        const userResponse = await env.USER_SERVICE.fetch(
          new Request(`http://internal/api/users/${userId}`)
        );
        if (userResponse.ok) {
          const data = await userResponse.json();
          userData = data.user;
        }
      }

      const total = productData ? productData.price * quantity : 0;
      const order = {
        id: Date.now(),
        userId,
        productId,
        quantity,
        total,
        status: 'pending',
        user: userData,
        product: productData
      };

      if (env.ANALYTICS_SERVICE) {
        await env.ANALYTICS_SERVICE.fetch(new Request('http://internal/api/analytics/track', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            event: 'order_created',
            data: { orderId: order.id, userId, productId, total },
            timestamp: Date.now()
          })
        }));
      }

      return new Response(JSON.stringify({
        order,
        message: 'Order created successfully'
      }), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (request.method === 'GET' && path.match(/^\/api\/orders\/\d+$/)) {
      const orderId = parseInt(path.split('/').pop());
      const order = {
        id: orderId,
        userId: 1,
        productId: 1,
        quantity: 2,
        total: 59.98,
        status: 'completed'
      };

      return new Response(JSON.stringify({ order }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Not found' }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

// worker-analytics-service.js - Analytics service internal worker
const events = [];

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const path = url.pathname;

    if (path === '/health') {
      return new Response(JSON.stringify({ status: 'healthy', service: 'analytics-service' }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (request.method === 'POST' && path === '/api/analytics/track') {
      const body = await request.json();
      events.push({
        ...body,
        receivedAt: Date.now()
      });

      return new Response(JSON.stringify({
        message: 'Event tracked successfully',
        event: body.event
      }), {
        status: 201,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (request.method === 'GET' && path === '/api/analytics') {
      return new Response(JSON.stringify({
        events: events.slice(-100),
        totalEvents: events.length
      }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    if (request.method === 'GET' && path === '/api/analytics/stats') {
      const eventsByType = events.reduce((acc, event) => {
        acc[event.event] = (acc[event.event] || 0) + 1;
        return acc;
      }, {});

      return new Response(JSON.stringify({
        totalEvents: events.length,
        eventsByType,
        lastEvent: events[events.length - 1] || null
      }), {
        headers: { 'Content-Type': 'application/json' }
      });
    }

    return new Response(JSON.stringify({ error: 'Not found' }), {
      status: 404,
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

